INSERT INTO `sys_movie` VALUES (32, '长津湖', 176, '["/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg"]', '中国大陆', '2021-09-30 00:00:00', 577535.00, '1950年，中国志愿军部队在极度严酷环境下坚守阵地奋勇杀敌，为长津湖战役胜利作出重要贡献的历史故事。', '["/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg", "/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (33, '红海行动', 138, '["/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg"]', '中国大陆', '2018-02-16 00:00:00', 365250.00, '中国海军蛟龙突击队8人小组奉命执行撤侨任务，在异国他乡遭遇伏击，突击队成员浴血奋战解救人质的故事。', '["/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg", "/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (34, '八佰', 147, '["/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg"]', '中国大陆', '2020-08-21 00:00:00', 311100.00, '1937年淞沪会战末期，国民革命军第88师524团留守上海四行仓库，与租界一河之隔，孤军奋战四昼夜的壮烈故事。', '["/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg", "/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (35, '敦刻尔克', 107, '["/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg"]', '英国/美国', '2017-07-21 00:00:00', 34100.00, '二战期间，英法联军被敌军包围在敦刻尔克海滩，英国政府和海军发动大批船员和民众营救被困士兵的故事。', '["/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg", "/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (36, '拯救大兵瑞恩', 169, '["/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg"]', '美国', '1998-07-24 00:00:00', 48000.00, '二战期间，一支美军小队深入敌后，冒着生命危险寻找并带回一名失去了三个兄长的伞兵瑞恩。', '["/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg", "/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (37, '满江红', 159, '["/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg"]', '中国大陆', '2023-01-22 00:00:00', 454400.00, '南宋绍兴年间，岳飞死后四年，秦桧率兵与金国会谈。一个小兵与亲兵营副统领被迫卷入一场巨大的阴谋中。', '["/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg", "/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (38, '妖猫传', 129, '["/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg"]', '中国大陆', '2017-12-22 00:00:00', 52900.00, '盛唐时期，一只口吐人言的妖猫在长安城掀起骚动，诗人白乐天与僧人空海联手调查妖猫背后的秘密。', '["/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg", "/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (39, '影', 116, '["/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg"]', '中国大陆', '2018-09-30 00:00:00', 62900.00, '一个从小被秘密囚禁的替身「影子」，在主人遇刺后被迫扮演主人角色，周旋于朝堂与战场之间。', '["/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg", "/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (40, '绣春刀II：修罗战场', 120, '["/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg"]', '中国大陆', '2017-07-19 00:00:00', 26500.00, '明天启年间，北镇抚司锦衣卫沈炼在追查案件中身陷阴谋，为了证明清白与少女北斋等人一同反抗追捕。', '["/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg", "/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (41, '卧虎藏龙', 120, '["/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg"]', '中国大陆/美国', '2000-07-06 00:00:00', 21300.00, '一代大侠李慕白欲退出江湖，托付红颜知己俞秀莲将自己的青冥剑带到京城，不料引发了一系列江湖恩怨。', '["/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg", "/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (42, '英雄', 99, '["/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg"]', '中国大陆', '2002-12-19 00:00:00', 25000.00, '战国时期，刺客无名以杀死三位绝世剑客为筹码接近秦王，在讲述过程中揭示了一个关于牺牲与天下的故事。', '["/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg", "/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (43, '一代宗师', 130, '["/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg"]', '中国大陆/中国香港', '2013-01-08 00:00:00', 28800.00, '民国时期，咏春拳宗师叶问从佛山到香港，历经时代变迁，最终将咏春拳发扬光大的传奇一生。', '["/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg", "/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (44, '剑雨', 120, '["/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg"]', '中国大陆/中国香港', '2010-09-28 00:00:00', 6700.00, '江湖中流传着一具可以令人起死回生的罗摩遗体，引来了各方势力的争夺。杀手细雨在易容后隐于市井，却再次被卷入风波。', '["/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg", "/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (45, '被解救的姜戈', 165, '["/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg"]', '美国', '2012-12-25 00:00:00', 42500.00, '1858年美国南部，赏金猎人舒尔茨解救黑奴姜戈，两人结伴展开复仇之旅，对抗残暴的糖果庄园主人。', '["/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg", "/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (46, '黄金三镖客', 178, '["/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg"]', '意大利/西班牙', '1966-12-23 00:00:00', 2500.00, '三个各自为政的亡命之徒，在南北战争的混乱背景下，为了寻找一笔巨额黄金而展开尔虞我诈的冒险。', '["/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg", "/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (47, '荒野猎人', 156, '["/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg"]', '美国', '2015-12-25 00:00:00', 53300.00, '19世纪美国西部，皮草猎人休·格拉斯在荒野中被同伴背叛抛弃，凭借顽强意志在冰天雪地中艰难求生并寻求复仇。', '["/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg", "/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (48, '八恶人', 187, '["/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg"]', '美国', '2015-12-25 00:00:00', 15600.00, '南北战争后数年，八名身份各异的陌生人在暴风雪中被困于山间驿站，彼此猜忌和阴谋逐渐浮出水面。', '["/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg", "/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (49, '大地惊雷', 110, '["/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg"]', '美国', '2010-12-22 00:00:00', 25200.00, '一个14岁女孩为了替父报仇，雇佣了酗酒的老警长，两人在追踪凶手的过程中建立了深厚的友谊。', '["/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg", "/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (50, '奥本海默', 180, '["/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg"]', '美国', '2023-07-21 00:00:00', 95300.00, '理论物理学家罗伯特·奥本海默领导曼哈顿计划研发原子弹，随后面对核弹带来的道德困境和政治迫害。', '["/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg", "/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (51, '波西米亚狂想曲', 134, '["/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg"]', '英国/美国', '2018-11-02 00:00:00', 90300.00, '皇后乐队主唱弗雷迪·默丘里从无名之辈成长为摇滚巨星，以及乐队创作经典歌曲、在Live Aid演唱会上震撼演出的故事。', '["/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg", "/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (52, '至暗时刻', 125, '["/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg"]', '英国/美国', '2017-12-01 00:00:00', 17300.00, '二战前夕，温斯顿·丘吉尔临危受命担任英国首相，面临是向纳粹妥协还是团结人民奋起反抗的艰难抉择。', '["/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg", "/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (53, '美丽心灵', 135, '["/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg"]', '美国', '2001-12-21 00:00:00', 31600.00, '数学家约翰·纳什在研究生时期发表了博弈论，但他同时也在与精神分裂症做斗争，在妻子的支持下最终获得诺贝尔奖。', '["/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg", "/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (54, '社交网络', 120, '["/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg"]', '美国', '2010-10-01 00:00:00', 22500.00, '哈佛大学学生马克·扎克伯格创建Facebook的创业历程，以及随之而来的法律纠纷和友情破裂。', '["/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg", "/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (55, '爱乐之城', 128, '["/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg"]', '美国', '2016-12-25 00:00:00', 44700.00, '爵士钢琴家塞巴斯蒂安和怀揣演员梦想的米娅在洛杉矶相遇相爱，在追逐梦想的道路上相互鼓励却又面临现实的考验。', '["/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg", "/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (56, '马戏之王', 105, '["/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg"]', '美国', '2017-12-20 00:00:00', 43500.00, '出身底层的巴纳姆凭借想象力和魄力开创世界上第一家马戏团，将奇人异士汇聚一堂，创造了轰动一时的娱乐王国。', '["/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg", "/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (57, '悲惨世界', 157, '["/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg"]', '英国/美国', '2012-12-25 00:00:00', 44200.00, '19世纪法国，囚犯冉阿让在出狱后被主教的善行感化，从此改头换面重新做人，却始终被警长沙威追捕。', '["/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg", "/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (58, '妈妈咪呀', 108, '["/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg"]', '英国/美国', '2008-07-18 00:00:00', 61000.00, '即将结婚的苏菲偷看了母亲的日记，邀请了三位可能是她父亲的男人来参加婚礼，引发了一连串温馨又搞笑的事件。', '["/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg", "/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (59, '芝加哥', 113, '["/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg"]', '美国', '2002-12-27 00:00:00', 30700.00, '1920年代芝加哥，梦想成为明星的罗克茜因枪杀情人入狱，在监狱中她遇到了同样因杀人入狱的歌舞明星维尔玛。', '["/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg", "/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (60, '七宗罪', 127, '["/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg"]', '美国', '1995-09-22 00:00:00', 32700.00, '一位即将退休的老警探和一位年轻警探联手追查一名以七宗罪为主题进行连环杀人的变态凶手。', '["/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg", "/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (61, '洛城机密', 138, '["/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg"]', '美国', '1997-09-19 00:00:00', 12600.00, '1950年代洛杉矶，三名性格迥异的警察在调查一桩咖啡馆谋杀案时，逐渐揭开了警局内部深藏的巨大腐败阴谋。', '["/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg", "/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (62, '老无所依', 122, '["/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg"]', '美国', '2007-11-09 00:00:00', 17100.00, '德州猎人在荒野中发现了一笔毒品交易留下的巨款，决定据为己有，却引来了一个冷酷无情的杀手的追杀。', '["/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg", "/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (63, '罪恶之城', 124, '["/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg"]', '美国', '2005-04-01 00:00:00', 15900.00, '在虚构的罪恶之城中，三段暴力血腥的故事交织：一个警察为爱报仇，一个街头混混卷入帮派战争，一个杀手保护无辜少女。', '["/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg", "/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (64, '日落大道', 110, '["/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg"]', '美国', '1950-08-10 00:00:00', 800.00, '一个落魄编剧误入过气默片女明星的豪宅，被其精神控制和情感绑架，逐渐陷入疯狂与悲剧。', '["/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg", "/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (65, '闪灵', 146, '["/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg"]', '英国/美国', '1980-05-23 00:00:00', 4500.00, '作家杰克带着妻儿来到偏僻的山顶酒店担任冬季看守，酒店中邪恶的超自然力量逐渐将他逼向疯狂。', '["/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg", "/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (66, '招魂', 112, '["/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg"]', '美国', '2013-07-19 00:00:00', 32000.00, '灵异调查者沃伦夫妇来到罗德岛的一座农舍，帮助一个被恶灵侵扰的家庭摆脱恐怖的超自然现象。', '["/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg", "/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (67, '小丑回魂', 135, '["/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg"]', '美国', '2017-09-08 00:00:00', 70000.00, '小镇德里每隔27年就会发生儿童失踪事件，一群自称「失败者俱乐部」的孩子决定联手对抗以恐惧为食的邪恶小丑。', '["/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg", "/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (68, '潜伏', 103, '["/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg"]', '美国', '2010-04-01 00:00:00', 10000.00, '一家人搬入新房后，儿子莫名陷入昏迷，而家中开始出现各种灵异现象。原来孩子的灵魂迷失在了黑暗的灵界之中。', '["/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg", "/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (69, '摔跤吧！爸爸', 161, '["/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg"]', '印度', '2016-12-23 00:00:00', 129800.00, '前摔跤冠军马哈维亚发现两个女儿有摔跤天赋，不顾社会偏见严格训练她们，最终培养出国际级女子摔跤冠军的感人故事。', '["/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg", "/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (70, '极速车王', 152, '["/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg"]', '美国', '2019-11-15 00:00:00', 22500.00, '汽车设计师卡罗尔·谢尔比和车手肯·迈尔斯联手为福特打造赛车，在1966年勒芒24小时耐力赛上与法拉利一决高下。', '["/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg", "/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (71, '光荣之路', 118, '["/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg"]', '美国', '2006-01-13 00:00:00', 5000.00, '1966年，白人教练唐·哈斯金斯招募黑人球员组建篮球队，在种族歧视严重的年代带领队伍闯入NCAA决赛的传奇。', '["/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg", "/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (72, '点球成金', 133, '["/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg"]', '美国', '2011-09-23 00:00:00', 11000.00, '奥克兰运动家棒球队总经理比利·比恩用数据分析和有限预算组建了一支有竞争力的球队，彻底改变了棒球界的运作方式。', '["/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg", "/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (73, '寻梦环游记', 105, '["/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg"]', '美国', '2017-11-22 00:00:00', 121200.00, '热爱音乐的小男孩米格在亡灵节误入亡灵世界，与已故曾曾祖父一起踏上了寻找回家之路的奇妙冒险。', '["/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg", "/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (74, '飞屋环游记', 96, '["/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg"]', '美国', '2009-05-29 00:00:00', 73500.00, '78岁的老人卡尔用数千个气球将房子升上天空前往南美，途中意外带上了一个8岁的小男孩，开启了一段冒险旅程。', '["/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg", "/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (75, '海蒂和爷爷', 111, '["/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg"]', '德国/瑞士', '2015-12-10 00:00:00', 1500.00, '孤儿海蒂被送到阿尔卑斯山上与性格孤僻的爷爷同住，她纯真的心灵融化了爷爷的冷漠，也温暖了身边的每一个人。', '["/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg", "/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (76, '奇迹男孩', 113, '["/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg"]', '美国', '2017-11-17 00:00:00', 28600.00, '天生面部畸形的10岁男孩奥吉第一次进入普通学校读书，在家人和朋友的支持下，他用勇气和善良赢得了所有人的尊重。', '["/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg", "/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (77, '末代皇帝', 163, '["/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg"]', '意大利/英国/中国', '1987-10-23 00:00:00', 4400.00, '从三岁登基到成为战犯被改造，爱新觉罗·溥仪经历了中国近代最动荡的时代，他的一生是个人与历史的悲剧交织。', '["/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg", "/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (78, '辛德勒的名单', 195, '["/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg"]', '美国', '1993-12-15 00:00:00', 32200.00, '二战期间，德国商人奥斯卡·辛德勒目睹犹太人遭受的迫害后，倾尽家财拯救了1100多名犹太人的生命。', '["/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg", "/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (79, '勇敢的心', 178, '["/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg"]', '美国', '1995-05-24 00:00:00', 21000.00, '13世纪末苏格兰起义领袖威廉·华莱士带领苏格兰人民反抗英格兰统治，为自由而战的悲壮史诗。', '["/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg", "/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (80, '珍珠港', 183, '["/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg"]', '美国', '2001-05-25 00:00:00', 44900.00, '1941年日军偷袭珍珠港前后，两名美军飞行员与一名护士之间发生的爱情故事，以及战争带来的巨大改变。', '["/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg", "/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (81, '鹬', 6, '["/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg"]', '美国', '2016-06-17 00:00:00', 0.00, '一只胆小的鹬鸟宝宝在妈妈的引导下，克服对海浪的恐惧，学会了自己在沙滩上觅食的有趣故事。', '["/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg", "/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (82, '美味盛宴', 6, '["/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg"]', '美国', '2014-06-10 00:00:00', 0.00, '一只小狗通过主人每天喂给它的食物，见证了主人从单身、恋爱、分手到复合的整个人生历程。', '["/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg", "/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (83, '纸人', 7, '["/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg"]', '美国', '2012-06-19 00:00:00', 0.00, '1940年代的纽约，一个年轻白领在地铁站邂逅心仪女孩后，用纸飞机不断尝试引起对方注意的浪漫故事。', '["/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg", "/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (84, '冲破天际', 12, '["/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg"]', '中国', '2018-10-01 00:00:00', 500.00, '一位从小梦想成为航天员的中国女孩，在童年伙伴的鼓励下冲破重重困难，最终实现太空梦想的励志故事。', '["/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg", "/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (85, '地球脉动 第二季', 360, '["/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg"]', '英国', '2016-11-06 00:00:00', 0.00, '自然纪录片大师大卫·爱登堡解说，展现地球上从高山到海洋、从沙漠到极地最壮丽的自然景观和野生动物奇观。', '["/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg", "/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (86, '海洋', 104, '["/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg"]', '法国/瑞士', '2009-10-17 00:00:00', 8200.00, '潜入海洋深处，探索一个你从未见过的神奇海底世界，与鲸鱼共舞，与鲨鱼擦肩，感受海洋的壮阔与脆弱。', '["/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg", "/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (87, '二十二', 99, '["/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg"]', '中国', '2017-08-14 00:00:00', 17100.00, '记录了2014年中国内地仅剩的22位「慰安妇」幸存者的真实生活，是她们最后一次用生命讲述那段苦难历史。', '["/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg", "/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (88, '我在故宫修文物', 86, '["/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg"]', '中国', '2016-12-16 00:00:00', 6300.00, '走进故宫博物院的文物修复室，近距离记录文物修复师们如何用精湛的技艺和极致的耐心让千年文物重焕光彩。', '["/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg", "/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (122, '包宝宝', 8, '["/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg"]', '美国', '2018-06-15 00:00:00', 0.00, '一位华裔母亲做的包子突然活了过来变成了包宝宝，她经历了养育孩子的全过程，从欣喜到失落再到和解的温暖故事。', '["/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg", "/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (123, '天地玄黄', 96, '["/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg"]', '美国', '1992-09-15 00:00:00', 0.00, '没有对白的纪录片杰作，用纯粹的影像跨越六大洲24个国家，展现自然之美、人类文明的庄严与工业化带来的冲击。', '["/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg", "/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (89, '禁闭岛', 138, '["/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg"]', '美国', '2010-02-19 00:00:00', 29500.00, '联邦警官泰迪来到禁闭岛精神病院调查一桩失踪案，但随着调查深入，他发现岛上隐藏着不可告人的秘密。', '["/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg", "/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (90, '消失的爱人', 149, '["/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg"]', '美国', '2014-10-03 00:00:00', 36900.00, '结婚五周年纪念日当天，妻子艾米离奇失踪，丈夫尼克成为头号嫌疑人。随着真相逐渐浮出水面，完美的婚姻面具被层层撕开。', '["/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg", "/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (91, '寄生虫', 132, '["/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg"]', '韩国', '2019-05-30 00:00:00', 25200.00, '一个住在半地下室的无业家庭，通过精心策划逐步渗透进一个富裕家庭，但一起意外事件让两个家庭的命运产生了惊天的交集。', '["/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg", "/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (92, '少年派的奇幻漂流', 127, '["/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg"]', '美国', '2012-11-21 00:00:00', 60900.00, '印度少年派在船难后与一只孟加拉虎同乘一艘救生艇在太平洋上漂流227天，展开了一段关于生存、信仰和奇迹的旅程。', '["/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg", "/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (93, '盗梦空间', 148, '["/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg"]', '美国/英国', '2010-07-16 00:00:00', 83600.00, '经验丰富的盗梦者柯布专门潜入他人梦境窃取秘密，为换取回家的机会，他接受了一个被认为不可能的任务——植入想法。', '["/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg", "/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (94, '指环王：护戒使者', 178, '["/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg"]', '新西兰/美国', '2001-12-19 00:00:00', 88300.00, '在古老的中土世界，霍比特人弗罗多继承了一枚拥有无上力量的至尊魔戒，他必须与伙伴们踏上销毁魔戒的冒险之旅。', '["/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg", "/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (95, '哈利·波特与魔法石', 152, '["/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg"]', '英国/美国', '2001-11-16 00:00:00', 97400.00, '11岁的哈利·波特收到霍格沃茨魔法学校的录取通知书，从此进入了一个充满魔法、友情和冒险的全新世界。', '["/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg", "/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (96, '千与千寻', 125, '["/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg"]', '日本', '2001-07-20 00:00:00', 36000.00, '10岁女孩千寻随父母搬家的途中意外进入了神灵的世界，她必须在汤婆婆的汤屋中努力工作，才能拯救变成猪的父母。', '["/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg", "/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (97, '阿凡达', 162, '["/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg"]', '美国', '2009-12-18 00:00:00', 273800.00, '前海军陆战队员杰克来到潘多拉星球，融入纳美族后爱上了这片土地和族人，最终带领纳美族抵抗人类的侵略。', '["/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg", "/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (98, '星际穿越', 169, '["/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg"]', '美国/英国', '2014-11-07 00:00:00', 67800.00, '在地球资源枯竭的未来，前NASA飞行员库珀穿越虫洞前往另一个星系，为人类寻找新的家园，却面临着时间与情感的巨大考验。', '["/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg", "/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (99, '流浪地球2', 173, '["/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg"]', '中国', '2023-01-22 00:00:00', 402800.00, '太阳急速老化膨胀，人类在地球表面建造出上万座行星发动机，推动地球离开太阳系，踏上长达2500年的宇宙流浪之旅。', '["/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg", "/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (100, '看不见的客人', 106, '["/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg"]', '西班牙', '2016-09-23 00:00:00', 17200.00, '成功企业家阿德里安被指控谋杀情人，他请来最好的律师为自己辩护。在案发前的最后几小时，真相与谎言不断交锋。', '["/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg", "/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (101, '记忆碎片', 113, '["/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg"]', '美国', '2000-09-05 00:00:00', 4000.00, '患上短期失忆症的莱纳只能记住几分钟前发生的事，他靠着纹身和便条追踪杀害妻子的凶手，但真相远比想象中复杂。', '["/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg", "/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (102, '教父', 175, '["/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg"]', '美国', '1972-03-24 00:00:00', 24600.00, '维托·柯里昂是纽约最有势力的黑手党家族首领，他的小儿子迈克尔从不愿涉足家族事务到最终继承父业成为新一代教父。', '["/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg", "/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (103, '楚门的世界', 103, '["/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg"]', '美国', '1998-06-05 00:00:00', 24800.00, '保险推销员楚门从出生起就生活在一个巨大的电视真人秀中，他周围的一切都是假的。当他发现真相后，决意逃离这个虚假的世界。', '["/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg", "/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (104, '肖申克的救赎', 142, '["/images/movie/2023/07/08/383abfce44934bbcb6441715979ca079.jpeg"]', '美国', '1994-09-23 00:00:00', 28300.00, '银行家安迪被冤入狱，在肖申克监狱中他用智慧和毅力赢得了尊重，并用二十年时间策划了一场不可思议的越狱计划。', '["/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg", "/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (105, '泰坦尼克号', 194, '["/images/movie/2023/07/08/38ed7dfa541341bcbbcabd097ffb2598.jpg"]', '美国', '1997-12-19 00:00:00', 219800.00, '1912年泰坦尼克号处女航中，贵族少女露丝与穷画家杰克的跨阶级爱情故事，随着巨轮沉没而成为永恒的经典。', '["/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg", "/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (106, '疯狂动物城', 109, '["/images/movie/2023/07/08/3ce7ec91b3c14c398e7595ff7fc435cf.jpeg"]', '美国', '2016-03-04 00:00:00', 153000.00, '在动物大都会中，兔子朱迪打破偏见成为第一名兔子警官，与狐狸尼克联手侦破了一桩动物失踪案。', '["/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg", "/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg"]', 0);
INSERT INTO `sys_movie` VALUES (107, '让子弹飞', 132, '["/images/movie/2023/07/08/487d7c27d8234044b860e6d2a10123bf.jpg"]', '中国大陆', '2010-12-16 00:00:00', 65500.00, '北洋年间，悍匪张牧之冒充县长走马上任鹅城，与当地恶霸黄四郎展开了一场斗智斗勇的较量。', '["/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg", "/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (108, '大鱼海棠', 105, '["/images/movie/2023/07/08/49f7835cda2949b4b1ab93070ac95a15.jpeg"]', '中国', '2016-07-08 00:00:00', 56500.00, '生活在神之围楼的少女椿，为了报恩而养育一个人类男孩的灵魂——一条小鱼，为此她不惜与整个世界对抗。', '["/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg", "/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (109, '哪吒之魔童降世', 110, '["/images/movie/2023/07/08/4a13f8fac2e54728bd8050a890c2b3fe.jpg"]', '中国', '2019-07-26 00:00:00', 503500.00, '天地灵气孕育出一颗混元珠，元始天尊将其分为灵珠和魔丸。魔丸投胎为哪吒，虽生而为魔却逆天改命的故事。', '["/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg", "/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (110, '姜子牙', 110, '["/images/movie/2023/07/08/4b28a354249b46a19aee33da8b7e6977.jpg"]', '中国', '2020-10-01 00:00:00', 160300.00, '封神大战后，昆仑弟子姜子牙因一时之过被贬下凡间。十年后，他在追寻真相的道路上发现了封神大战背后的惊天阴谋。', '["/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg", "/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (111, '白蛇：缘起', 99, '["/images/movie/2023/07/08/50ad852d85704661818907b6fa8a809c.jpg"]', '中国', '2019-01-11 00:00:00', 46800.00, '晚唐年间，国师发动民众大量捕蛇。前去刺杀国师的白蛇在失忆后被捕蛇村少年阿宣救起，两人在追捕中产生了深厚的感情。', '["/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg", "/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (112, '大圣归来', 89, '["/images/movie/2023/07/08/05dc8e859d464d4eab415398abe29e7d.jpg"]', '中国', '2015-07-10 00:00:00', 95600.00, '被压在五行山下五百年的孙悟空，偶然被小和尚江流儿解除封印，在相互陪伴的冒险中重拾勇气与责任。', '["/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg", "/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (113, '独行月球', 122, '["/images/movie/2023/07/08/08cbbda0dce14d26a7827803df275b88.jpg"]', '中国', '2022-07-29 00:00:00', 310300.00, '人类在月球部署了月盾计划，陨石提前来袭全员撤离时维修工独孤月被意外落在月球，开始了他在月球上破罐破摔的独居生活。', '["/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg", "/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (114, '你好，李焕英', 128, '["/images/movie/2023/07/08/0e21bc454f54498193bf8d49a84941f0.jpg"]', '中国', '2021-02-12 00:00:00', 541300.00, '刚考上大学的贾晓玲意外穿越回1981年，与正值青春的母亲李焕英相遇，她想方设法让妈妈过得更好，却揭开了妈妈深藏的秘密。', '["/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg", "/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (115, '唐人街探案3', 136, '["/images/movie/2023/07/08/12224d79b05743e894d95f94fa16b63c.jpg"]', '中国', '2021-02-12 00:00:00', 452200.00, '唐仁和秦风受邀到东京调查一桩离奇谋杀案，与各国神探展开了一场智力与笑料齐飞的探案之旅。', '["/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg", "/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (116, '长空之王', 128, '["/images/movie/2023/07/08/175aa5b46b8245c4af7d8ed6ebc9da0e.jpg"]', '中国', '2023-04-28 00:00:00', 84600.00, '雷宇等优秀飞行员经过严苛选拔成为试飞员，在队长张挺的带领下，参与最新型战机的试飞，不断挑战战机和自我的极限。', '["/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg", "/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (117, '人生大事', 112, '["/images/movie/2023/07/08/22503c98b340436580cf12b154d8ae29.jpg"]', '中国', '2022-06-24 00:00:00', 171300.00, '刑满释放的殡葬师莫三妹在一次出殡中遇到了孤儿武小文，小文的出现意外地改变了莫三妹对职业和生活的态度。', '["/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg", "/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (118, '这个杀手不太冷静', 109, '["/images/movie/2023/07/08/251ad032e1d04ca4b41c6d5dc545439b.jpg"]', '中国', '2022-02-01 00:00:00', 262800.00, '龙套演员魏成功得到了女明星米兰的赏识，被邀请出演男一号神秘杀手，却不知道这场戏的背后隐藏着一个巨大的危险。', '["/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg", "/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (119, '万里归途', 137, '["/images/movie/2023/07/08/272661536e044168befb799e85a6b934.jpg"]', '中国', '2022-09-30 00:00:00', 159400.00, '北非努米亚爆发战乱，前驻地外交官宗大伟与新人成朗受命前往协助撤侨，在战火纷飞中带领同胞走出一条归家之路。', '["/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg", "/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (120, '人生路不熟', 100, '["/images/movie/2023/07/08/2bc813e9e2f74b5489cb5d165ceb351d.jpg"]', '中国', '2023-04-28 00:00:00', 121300.00, '一家四口在旅途中阴差阳错地卷入一场与油耗子的较量，卡车司机周东海和准女婿万一帆在磕磕碰碰中互相了解。', '["/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg", "/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg"]', 0);
INSERT INTO `sys_movie` VALUES (121, '深海', 112, '["/images/movie/2023/07/08/2d049461480946478e34524fc96a3b16.jpg"]', '中国', '2023-01-22 00:00:00', 91900.00, '一个小女孩在奇幻的海底世界中展开了一段独特的冒险，在绚烂多彩的深海大饭店中寻找妈妈的身影。', '["/images/movie/2023/07/08/2edebbc29c4c4b8491d45cd85bbfd49d.jpg", "/images/movie/2023/07/08/381d7593694d4952b62a003b7f8ef425.jpeg"]', 0);
